diff --git a/llvm/lib/Analysis/ValueTracking.cpp b/llvm/lib/Analysis/ValueTracking.cpp
index 28d7e1ce401e..ff966071d012 100644
--- a/llvm/lib/Analysis/ValueTracking.cpp
+++ b/llvm/lib/Analysis/ValueTracking.cpp
@@ -3020,8 +3020,12 @@ static bool isKnownNonZeroFromOperator(const Operator *I,
     if (matchOpWithOpEqZero(I->getOperand(0), I->getOperand(1)))
       return true;
     // X | Y != 0 if X != 0 or Y != 0.
-    return isKnownNonZero(I->getOperand(1), DemandedElts, Q, Depth) ||
-           isKnownNonZero(I->getOperand(0), DemandedElts, Q, Depth);
+    if (isKnownNonZero(I->getOperand(1), DemandedElts, Q, Depth) ||
+        isKnownNonZero(I->getOperand(0), DemandedElts, Q, Depth))
+      return true;
+    // X | Y != 0 if X != Y (at least one must be non-zero).
+    return ::isKnownNonEqual(I->getOperand(0), I->getOperand(1), DemandedElts,
+                             Depth + 1, Q);
   case Instruction::SExt:
   case Instruction::ZExt:
     // ext X != 0 if X != 0.
diff --git a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
index 6dd26910f684..93b023a33300 100644
--- a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
+++ b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
@@ -1456,6 +1456,17 @@ static bool checkAndReplaceCondition(
     return true;
   };

+  // Check if icmp eq (or X, Y), 0 can be simplified when X != Y is known.
+  // If X != Y, then X | Y cannot be 0 (because if both were 0, they'd be equal).
+  Value *OrOp0, *OrOp1;
+  if (Cmp->getPredicate() == CmpInst::ICMP_EQ &&
+      match(Cmp->getOperand(0), m_Or(m_Value(OrOp0), m_Value(OrOp1))) &&
+      match(Cmp->getOperand(1), m_Zero())) {
+    // Check if OrOp0 != OrOp1 is known to hold.
+    if (Info.doesHold(CmpInst::ICMP_NE, OrOp0, OrOp1))
+      return ReplaceCmpWithConstant(Cmp, false);
+  }
+
   if (auto ImpliedCondition =
           checkCondition(Cmp->getPredicate(), Cmp->getOperand(0),
                          Cmp->getOperand(1), Cmp, Info))

