   483 | // Decomposes \p V into a constant offset + list of pairs { Coefficient,
   484 | // Variable } where Coefficient * Variable. The sum of the constant offset and
   485 | // pairs equals \p V.
   486 | static Decomposition decompose(Value *V,
   487 |                                SmallVectorImpl<ConditionTy> &Preconditions,
   488 |                                bool IsSigned, const DataLayout &DL) {
   489 | 
   490 |   auto MergeResults = [&Preconditions, IsSigned, &DL](Value *A, Value *B,
   491 |                                                       bool IsSignedB) {
   492 |     auto ResA = decompose(A, Preconditions, IsSigned, DL);
   493 |     auto ResB = decompose(B, Preconditions, IsSignedB, DL);
   494 |     ResA.add(ResB);
   495 |     return ResA;
   496 |   };
   497 | 
   498 |   Type *Ty = V->getType()->getScalarType();
   499 |   if (Ty->isPointerTy() && !IsSigned) {
   500 |     if (auto *GEP = dyn_cast<GEPOperator>(V))
   501 |       return decomposeGEP(*GEP, Preconditions, IsSigned, DL);
   502 |     if (isa<ConstantPointerNull>(V))
   503 |       return int64_t(0);
   504 | 
   505 |     return V;
   506 |   }
   507 | 
   508 |   // Don't handle integers > 64 bit. Our coefficients are 64-bit large, so
   509 |   // coefficient add/mul may wrap, while the operation in the full bit width
   510 |   // would not.
   511 |   if (!Ty->isIntegerTy() || Ty->getIntegerBitWidth() > 64)
