   533 |     }
   534 | 
   535 |     if (match(V, m_NSWAdd(m_Value(Op0), m_Value(Op1))))
   536 |       return MergeResults(Op0, Op1, IsSigned);
   537 | 
   538 |     if (match(V, m_NSWSub(m_Value(Op0), m_Value(Op1)))) {
   539 |       auto ResA = decompose(Op0, Preconditions, IsSigned, DL);
   540 |       auto ResB = decompose(Op1, Preconditions, IsSigned, DL);
